<?php require "vendor/autoload.php"; $app = require_once "bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $user = \App\Models\User::first(); $verificationUrl = \Illuminate\Support\Facades\URL::temporarySignedRoute("verification.verify", now()->addHours(24), ["id" => $user->id, "hash" => sha1($user->email)]); try { \Illuminate\Support\Facades\Mail::to($user->email)->send(new \App\Mail\VerificarCuenta($user, $verificationUrl)); echo "Sent\n"; } catch (\Exception $e) { echo "Error: " . $e->getMessage() . "\n"; }
